sql:
SELECT phu_id, phone
FROM public_health_units
ORDER BY phu_id ASC;

external_knowledge:
- 'Bloomed' refers to having more than 10 appointments;
- 'Average hour' is calculated by converting the first two characters of the `appointment_time` to a real number and then averaging these values;
- The time is in a 24-hour format.

sql:
SELECT COUNT(DISTINCT centre_id) AS total_centres_with_parking
FROM accessibility
WHERE feature = 'parking' AND details = 'Free parking available on-site';

SELECT equipment_name, quantity
FROM centre_equipment
WHERE quantity > 5;

external_knowledge:
- 'busiest' refers to the highest capacity utilization;
- 'most efficient' refers to the highest percentage of scheduled appointments;
- 'bees buzzing around' is a metaphor for a high number of appointments;
- 'honey jars ready for collection' is a metaphor for scheduled appointments.

- "blossoming with the fragrance of French language" refers to centres that offer services in French;
- "strength of COVID-19 Assessment services" refers to centres that provide the COVID-19 Assessment service;
- "nurturing presence of nurses" refers to centres that have at least one nurse on staff.

- "patient populations" can refer to groups of patients defined by specific criteria, such as symptomatic or asymptomatic;
- "staff members" are individuals with roles like nurse or doctor who provide services at health centers;
- "locations" are identified by their names, cities, and provinces.

sql:
SELECT COUNT(*) AS total_french_entries
FROM language
WHERE language = 'French';

SELECT phu, email
FROM public_health_units
WHERE phu LIKE 'Toronto%';

SELECT phu 
FROM public_health_units 
WHERE phu_id = 0;

SELECT test_name, COUNT(DISTINCT centre_id) AS centre_count
FROM test_types
GROUP BY test_name;

external_knowledge:
- 'Beacons of health' refers to assessment centres that provide essential health services;
- 'Serene morning hours' refers to the time slot between 9 AM and 12 PM;
- 'Under the watchful eye of the Public Health Unit' means the centres are associated with or managed by the Public Health Unit.

- 'asymptomatic' refers to patients who do not show symptoms of a disease;
- 'symptomatic' refers to patients who show symptoms of a disease;
- 'scheduled' appointments are those that are planned but not yet completed or cancelled.

sql:
SELECT name 
FROM staff 
WHERE centre_id = 2 AND phone LIKE '705%';

SELECT COUNT(DISTINCT centre_id) 
FROM centre_services 
WHERE service_name = 'COVID-19 Testing';

